import{_ as s,o as i,c as e,ai as l}from"./chunks/framework.CsYGeNYI.js";const k=JSON.parse('{"title":"Bonjour 设备发现","description":"","frontmatter":{"read_when":["在 macOS/iOS 上调试 Bonjour 设备发现问题时","更改 mDNS 服务类型、TXT 记录或设备发现用户体验时"],"summary":"Bonjour/mDNS 设备发现 + 调试（Gateway 网关信标、客户端和常见故障模式）","title":"Bonjour 设备发现","x-i18n":{"generated_at":"2026-02-03T07:47:48Z","model":"claude-opus-4-5","provider":"pi","source_hash":"47569da55f0c0523bd5ff05275dc95ccb52f75638193cfbdb4eaaa162aadf08c","source_path":"gateway/bonjour.md","workflow":15}},"headers":[],"relativePath":"zh-CN/gateway/bonjour.md","filePath":"zh-CN/gateway/bonjour.md","lastUpdated":null}'),n={name:"zh-CN/gateway/bonjour.md"};function t(o,a,d,h,p,c){return i(),e("div",null,[...a[0]||(a[0]=[l(`<h1 id="bonjour-mdns-设备发现" tabindex="-1"><a class="header-anchor" href="#bonjour-mdns-设备发现">#</a> Bonjour / mDNS 设备发现</h1><p>OpenSoul 使用 Bonjour（mDNS / DNS‑SD）作为<strong>仅限局域网的便捷方式</strong>来发现 活跃的 Gateway 网关（WebSocket 端点）。这是尽力而为的，<strong>不能</strong>替代 SSH 或 基于 Tailnet 的连接。</p><h2 id="通过-tailscale-的广域-bonjour-单播-dns‐sd" tabindex="-1"><a class="header-anchor" href="#通过-tailscale-的广域-bonjour-单播-dns‐sd">#</a> 通过 Tailscale 的广域 Bonjour（单播 DNS‑SD）</h2><p>如果节点和 Gateway 网关在不同的网络上，多播 mDNS 无法跨越 边界。你可以通过切换到基于 Tailscale 的<strong>单播 DNS‑SD</strong> （&quot;广域 Bonjour&quot;）来保持相同的设备发现用户体验。</p><p>概要步骤：</p><ol><li>在 Gateway 网关主机上运行 DNS 服务器（可通过 Tailnet 访问）。</li><li>在专用区域下发布 <code>_opensoul-gw._tcp</code> 的 DNS‑SD 记录 （示例：<code>opensoul.internal.</code>）。</li><li>配置 Tailscale <strong>分割 DNS</strong>，使你选择的域名通过该 DNS 服务器为客户端（包括 iOS）解析。</li></ol><p>OpenSoul 支持任何发现域名；<code>opensoul.internal.</code> 只是一个示例。 iOS/Android 节点同时浏览 <code>local.</code> 和你配置的广域域名。</p><h3 id="gateway-网关配置-推荐" tabindex="-1"><a class="header-anchor" href="#gateway-网关配置-推荐">#</a> Gateway 网关配置（推荐）</h3><div class="language-json5 vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  gateway</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">bind</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;tailnet&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> }, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 仅 tailnet（推荐）</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  discovery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">wideArea</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } }, </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// 启用广域 DNS-SD 发布</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="一次性-dns-服务器设置-gateway-网关主机" tabindex="-1"><a class="header-anchor" href="#一次性-dns-服务器设置-gateway-网关主机">#</a> 一次性 DNS 服务器设置（Gateway 网关主机）</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">opensoul</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dns</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> setup</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --apply</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>这会安装 CoreDNS 并配置它：</p><ul><li>仅在 Gateway 网关的 Tailscale 接口上监听 53 端口</li><li>从 <code>~/.opensoul/dns/&lt;domain&gt;.db</code> 提供你选择的域名服务（示例：<code>opensoul.internal.</code>）</li></ul><p>从 Tailnet 连接的机器上验证：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dns-sd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -B</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _opensoul-gw._tcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> opensoul.internal.</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">TAILNET_IPV</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">4&gt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -p</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 53</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _opensoul-gw._tcp.opensoul.internal</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> PTR</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +short</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h3 id="tailscale-dns-设置" tabindex="-1"><a class="header-anchor" href="#tailscale-dns-设置">#</a> Tailscale DNS 设置</h3><p>在 Tailscale 管理控制台中：</p><ul><li>添加指向 Gateway 网关 Tailnet IP 的名称服务器（UDP/TCP 53）。</li><li>添加分割 DNS，使你的发现域名使用该名称服务器。</li></ul><p>一旦客户端接受 Tailnet DNS，iOS 节点就可以在 你的发现域名中浏览 <code>_opensoul-gw._tcp</code>，无需多播。</p><h3 id="gateway-网关监听器安全-推荐" tabindex="-1"><a class="header-anchor" href="#gateway-网关监听器安全-推荐">#</a> Gateway 网关监听器安全（推荐）</h3><p>Gateway 网关 WS 端口（默认 <code>18789</code>）默认绑定到 loopback。对于局域网/Tailnet 访问，请明确绑定并保持认证启用。</p><p>对于仅 Tailnet 的设置：</p><ul><li>在 <code>~/.opensoul/opensoul.json</code> 中设置 <code>gateway.bind: &quot;tailnet&quot;</code>。</li><li>重启 Gateway 网关（或重启 macOS 菜单栏应用）。</li></ul><h2 id="什么在广播" tabindex="-1"><a class="header-anchor" href="#什么在广播">#</a> 什么在广播</h2><p>只有 Gateway 网关广播 <code>_opensoul-gw._tcp</code>。</p><h2 id="服务类型" tabindex="-1"><a class="header-anchor" href="#服务类型">#</a> 服务类型</h2><ul><li><code>_opensoul-gw._tcp</code> — Gateway 网关传输信标（被 macOS/iOS/Android 节点使用）。</li></ul><h2 id="txt-键-非机密提示" tabindex="-1"><a class="header-anchor" href="#txt-键-非机密提示">#</a> TXT 键（非机密提示）</h2><p>Gateway 网关广播小型非机密提示以方便 UI 流程：</p><ul><li><code>role=gateway</code></li><li><code>displayName=&lt;友好名称&gt;</code></li><li><code>lanHost=&lt;hostname&gt;.local</code></li><li><code>gatewayPort=&lt;port&gt;</code>（Gateway 网关 WS + HTTP）</li><li><code>gatewayTls=1</code>（仅当 TLS 启用时）</li><li><code>gatewayTlsSha256=&lt;sha256&gt;</code>（仅当 TLS 启用且指纹可用时）</li><li><code>canvasPort=&lt;port&gt;</code>（仅当画布主机启用时；默认 <code>18793</code>）</li><li><code>sshPort=&lt;port&gt;</code>（未覆盖时默认为 22）</li><li><code>transport=gateway</code></li><li><code>cliPath=&lt;path&gt;</code>（可选；可运行的 <code>opensoul</code> 入口点的绝对路径）</li><li><code>tailnetDns=&lt;magicdns&gt;</code>（当 Tailnet 可用时的可选提示）</li></ul><h2 id="在-macos-上调试" tabindex="-1"><a class="header-anchor" href="#在-macos-上调试">#</a> 在 macOS 上调试</h2><p>有用的内置工具：</p><ul><li>浏览实例：<div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dns-sd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -B</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _opensoul-gw._tcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li>解析单个实例（替换 <code>&lt;instance&gt;</code>）：<div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dns-sd</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -L</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;&lt;instance&gt;&quot;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> _opensoul-gw._tcp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> local.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li></ul><p>如果浏览有效但解析失败，你通常遇到的是局域网策略或 mDNS 解析器问题。</p><h2 id="在-gateway-网关日志中调试" tabindex="-1"><a class="header-anchor" href="#在-gateway-网关日志中调试">#</a> 在 Gateway 网关日志中调试</h2><p>Gateway 网关会写入滚动日志文件（启动时打印为 <code>gateway log file: ...</code>）。查找 <code>bonjour:</code> 行，特别是：</p><ul><li><code>bonjour: advertise failed ...</code></li><li><code>bonjour: ... name conflict resolved</code> / <code>hostname conflict resolved</code></li><li><code>bonjour: watchdog detected non-announced service ...</code></li></ul><h2 id="在-ios-节点上调试" tabindex="-1"><a class="header-anchor" href="#在-ios-节点上调试">#</a> 在 iOS 节点上调试</h2><p>iOS 节点使用 <code>NWBrowser</code> 来发现 <code>_opensoul-gw._tcp</code>。</p><p>要捕获日志：</p><ul><li>设置 → Gateway 网关 → 高级 → <strong>Discovery Debug Logs</strong></li><li>设置 → Gateway 网关 → 高级 → <strong>Discovery Logs</strong> → 复现 → <strong>Copy</strong></li></ul><p>日志包括浏览器状态转换和结果集变化。</p><h2 id="常见故障模式" tabindex="-1"><a class="header-anchor" href="#常见故障模式">#</a> 常见故障模式</h2><ul><li><strong>Bonjour 不能跨网络</strong>：使用 Tailnet 或 SSH。</li><li><strong>多播被阻止</strong>：某些 Wi‑Fi 网络禁用 mDNS。</li><li><strong>休眠 / 接口变动</strong>：macOS 可能暂时丢弃 mDNS 结果；重试。</li><li><strong>浏览有效但解析失败</strong>：保持机器名称简单（避免表情符号或 标点符号），然后重启 Gateway 网关。服务实例名称源自 主机名，因此过于复杂的名称可能会混淆某些解析器。</li></ul><h2 id="转义的实例名称-032" tabindex="-1"><a class="header-anchor" href="#转义的实例名称-032">#</a> 转义的实例名称（<code>\\032</code>）</h2><p>Bonjour/DNS‑SD 经常将服务实例名称中的字节转义为十进制 <code>\\DDD</code> 序列（例如空格变成 <code>\\032</code>）。</p><ul><li>这在协议级别是正常的。</li><li>UI 应该解码以进行显示（iOS 使用 <code>BonjourEscapes.decode</code>）。</li></ul><h2 id="禁用-配置" tabindex="-1"><a class="header-anchor" href="#禁用-配置">#</a> 禁用 / 配置</h2><ul><li><code>OPENSOUL_DISABLE_BONJOUR=1</code> 禁用广播（旧版：<code>OPENSOUL_DISABLE_BONJOUR</code>）。</li><li><code>~/.opensoul/opensoul.json</code> 中的 <code>gateway.bind</code> 控制 Gateway 网关绑定模式。</li><li><code>OPENSOUL_SSH_PORT</code> 覆盖 TXT 中广播的 SSH 端口（旧版：<code>OPENSOUL_SSH_PORT</code>）。</li><li><code>OPENSOUL_TAILNET_DNS</code> 在 TXT 中发布 MagicDNS 提示（旧版：<code>OPENSOUL_TAILNET_DNS</code>）。</li><li><code>OPENSOUL_CLI_PATH</code> 覆盖广播的 CLI 路径（旧版：<code>OPENSOUL_CLI_PATH</code>）。</li></ul><h2 id="相关文档" tabindex="-1"><a class="header-anchor" href="#相关文档">#</a> 相关文档</h2><ul><li>设备发现策略和传输选择：<a href="/docs/gateway/discovery">设备发现</a></li><li>节点配对 + 批准：<a href="/docs/gateway/pairing">Gateway 网关配对</a></li></ul>`,51)])])}const g=s(n,[["render",t]]);export{k as __pageData,g as default};
